package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/rooms/edit")public class RoomEditServlet extends RoomCreateServlet{protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Room x=s.getRoom(id).orElse(null);if(x==null){r.sendError(404);return;}RoomForm f=new RoomForm();f.setRoomId(x.getRoomId());f.setRoomNumber(x.getRoomNumber());f.setRoomType(x.getRoomType());f.setFloorNumber(x.getFloorNumber().toString());f.setDepartmentId(x.getDepartmentId());f.setDailyRate(x.getDailyRate().toString());f.setStatus(x.getStatus());q.setAttribute("roomForm",f);show(q,r,"EDIT");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{RoomForm f=form(q);ServiceResult<Void>x=s.updateRoom(f,AdmissionRequest.audit(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/rooms/view?id="+f.getRoomId());return;}q.setAttribute("roomForm",f);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,"EDIT");}}
